-- calendar_display_mode_setting
UPDATE `custom_settings` SET `value` = '{\n  \"enable_weekly_plan\": true,\n  \"enable_differential_display\": true,\n  \"call_state_to_be_compared\": [],\n  \"tot_state_to_be_compared\": [],\n  \"tot_type_mapping\": {\n    \"tot_type_id\": \"weekly_plan__tot_id\"\n  },\n  \"enable_call_finish_action\": true,\n  \"enable_coaching_finish_action\": true,\n  \"calendar_timeline\": {\n    \"every_day_range_time\": { \n      \"am\": [\n        \"08:00:00\",\n        \"12:00:00\" \n      ],\n      \"pm\": [  \n        \"12:00:00\",\n        \"16:00:00\"\n      ]\n    },\n    \"unknown_max_minutes\": 30,\n    \"objects\": {  \n      \"time_off_territory\": { \n        \"__default__\": {  \n          \"values\": { \n            \"am\": [  \n              \"forenoon\"\n            ],\n            \"pm\": [ \n              \"afternoon\"\n            ]\n          },\n          \"column_names\": [  \n            \"date\", \n            \"ampm\"\n          ],\n          \"type\": \"ampm\"\n        }\n      },\n      \"coaching\": {\n        \"__default__\": {\n          \"column_names\": [\n            \"coaching_date\"\n          ],\n          \"type\": \"date\"\n        }\n      },\n      \"call\": {\n        \"__default__\": {\n          \"column_names\": [\n            \"call_date\"\n          ],\n          \"type\": \"date\"\n        }\n      },\n      \"event\": {\n        \"__default__\": {\n          \"column_names\": [\n            \"event_start_time\",\n            \"event_end_time\"\n          ],\n          \"type\": \"range\"\n        }\n      },\n      \"weekly_plan\": {\n        \"__default__\": { \n          \"values\": {\n            \"am\": [\n              \"am\"\n            ],\n            \"pm\": [\n              \"pm\"\n            ]\n          },\n          \"column_names\": [\n            \"date\",\n            \"ampm\"\n          ],\n          \"type\": \"ampm\"\n        },\n        \"weekly_plan_coaching_plans\": {\n          \"column_names\": [\n      