UPDATE `custom_settings` SET `value` = '[\n    {\n        \"fields\": [\n            {\n                \"type\": \"date\",\n                \"name\": \"call_date\"\n            }\n        ],\n        \"object_name\": \"call\"\n    },\n    {\n        \"fields\": [\n            {\n                \"type\": \"date\",\n                \"name\": \"coaching_date\"\n            }\n        ],\n        \"object_name\": \"coaching\"\n    },\n    {\n        \"fields\": [\n        ],\n        \"object_name\": \"event\"\n    },\n    {\n        \"fields\": [\n            {\n                \"type\": \"datetime\",\n                \"name\": \"start_time\",\n                \"time_tag\": \"start\"\n            },\n            {\n                \"type\": \"datetime\",\n                \"name\": \"end_time\",\n                \"time_tag\": \"end\"\n            }\n        ],\n        \"object_name\": \"weekly_plan\"\n    },\n    {\n        \"fields\": [\n            {\n                \"type\": \"date\",\n                \"name\": \"date\"\n            }\n        ],\n        \"object_name\": \"time_off_territory\"\n    }\n]' WHERE (`key` = 'calendar_create_data_config');
